/// Look up an icon by exact name and optional exact mimetype.
pub(crate) fn lookup(name: &str, mimetype: Option<&str>) -> Option<&'static Icon> {
    match (name, mimetype) {
        ("document", Some("text/rich")) => Some(&ICON_DOCUMENT_TEXT_RICH),
        ("document", Some("text/markdown")) => Some(&ICON_DOCUMENT_TEXT_MARKDOWN),
        ("document", Some("application/json")) => Some(&ICON_DOCUMENT_APPLICATION_JSON),
        ("document", Some("text/csv")) => Some(&ICON_DOCUMENT_TEXT_CSV),
        ("document", None) => Some(&ICON_DOCUMENT),
        ("search", None) => Some(&ICON_SEARCH),
        ("settings", None) => Some(&ICON_SETTINGS),
        ("alert", None) => Some(&ICON_ALERT),
        ("info", None) => Some(&ICON_INFO),
        ("check", None) => Some(&ICON_CHECK),
        ("close", None) => Some(&ICON_CLOSE),
        ("plus", None) => Some(&ICON_PLUS),
        ("minus", None) => Some(&ICON_MINUS),
        ("arrow-left", None) => Some(&ICON_ARROW_LEFT),
        ("arrow-right", None) => Some(&ICON_ARROW_RIGHT),
        ("arrow-up", None) => Some(&ICON_ARROW_UP),
        ("arrow-down", None) => Some(&ICON_ARROW_DOWN),
        ("undo", None) => Some(&ICON_UNDO),
        ("redo", None) => Some(&ICON_REDO),
        ("menu", None) => Some(&ICON_MENU),
        ("loading", None) => Some(&ICON_LOADING),
        _ => None,
    }
}

/// Look up an icon by name and mimetype category prefix.
pub(crate) fn lookup_category(name: &str, category: &str) -> Option<&'static Icon> {
    match (name, category) {
        ("document", "text/") => Some(&ICON_DOCUMENT_CAT_TEXT),
        ("document", "image/") => Some(&ICON_DOCUMENT_CAT_IMAGE),
        ("document", "audio/") => Some(&ICON_DOCUMENT_CAT_AUDIO),
        ("document", "video/") => Some(&ICON_DOCUMENT_CAT_VIDEO),
        _ => None,
    }
}

/// Universal fallback icon (base document).
pub(crate) fn fallback() -> &'static Icon {
    &ICON_DOCUMENT
}
